// 이메일 HTML에서 '수신문서보기' 버튼 URL 추출
const emails = $input.all();
let docUrl = null;
let targetEmail = null;

for (const emailItem of emails) {
  const email = emailItem.json;
  const html = email.html || '';
  if (!html) continue;

  // 패턴1: <a href="...">수신문서보기</a>
  const p1 = /<a[^>]+href=['"]([^'"]+)['"][^>]*>[^<]*수신문서[^<]*<\/a>/gi;
  let m = p1.exec(html);
  if (m) {
    docUrl = m[1].startsWith('http') ? m[1] : 'https:' + m[1];
    targetEmail = email;
    break;
  }

  // 패턴2: '수신문서보기' 텍스트 주변 href 탐색
  const idx = html.indexOf('수신문서보기');
  if (idx > -1) {
    const nearby = html.substring(Math.max(0, idx - 400), idx + 400);
    const hm = nearby.match(/href=['"]([^'"]+)['"]/i);
    if (hm) {
      docUrl = hm[1].startsWith('http') ? hm[1] : 'https:' + hm[1];
      targetEmail = email;
      break;
    }
    const om = nearby.match(/window\.open\(['"]([^'"]+)['"]/i);
    if (om) { docUrl = om[1]; targetEmail = email; break; }
  }

  // 패턴3: 거래명세서 관련 도메인 URL
  const p3 = /href=['"]([^'"]*(?:bizboard|etrade|trade|document|명세서)[^'"]*)['"]>/gi;
  const tm = p3.exec(html);
  if (tm) {
    docUrl = tm[1].startsWith('http') ? tm[1] : 'https:' + tm[1];
    targetEmail = email;
    break;
  }
}

if (!targetEmail && emails.length > 0) targetEmail = emails[0].json;

return [{
  json: {
    subject: targetEmail?.subject || '(제목없음)',
    from: targetEmail?.from || '',
    date: targetEmail?.date || '',
    docUrl: docUrl,
    docUrlFound: !!docUrl,
    emailCount: emails.length
  }
}];

// 거래명세서 HTML에서 구조화 데이터 추출
const html = $input.first().json.data || '';

function clean(h) {
  return h.replace(/<br\s*\/?>/gi, ' ')
          .replace(/<[^>]+>/g, '')
          .replace(/&nbsp;/g, ' ')
          .replace(/&amp;/g, '&')
          .replace(/&lt;/g, '<')
          .replace(/&gt;/g, '>')
          .replace(/&quot;/g, '"')
          .replace(/\s+/g, ' ').trim();
}

function parseTables(html) {
  const tables = [];
  const trx = /<table[\s\S]*?<\/table>/gi;
  let tm;
  while ((tm = trx.exec(html)) !== null) {
    const rows = [];
    const rrx = /<tr[^>]*>([\s\S]*?)<\/tr>/gi;
    let rm;
    while ((rm = rrx.exec(tm[0])) !== null) {
      const cells = [];
      const crx = /<t[dh][^>]*>([\s\S]*?)<\/t[dh]>/gi;
      let cm;
      while ((cm = crx.exec(rm[1])) !== null) cells.push(clean(cm[1]));
      if (cells.some(c => c)) rows.push(cells);
    }
    if (rows.length) tables.push(rows);
  }
  return tables;
}

const tables = parseTables(html);
const text = clean(html);

// 품목 테이블 탐지
const KEYS = ['품목', '수량', '단가', '금액', '공급가액', '규격'];
const itemTable = tables.find(t =>
  t.length >= 2 && t[0].some(c => KEYS.some(k => c.includes(k)))
);

let 품목목록 = [];
if (itemTable) {
  const headers = itemTable[0];
  품목목록 = itemTable.slice(1)
    .filter(r => r.some(c => c.trim()))
    .map(r => {
      const obj = {};
      headers.forEach((h, i) => { if (h.trim()) obj[h.trim()] = (r[i] || '').trim(); });
      return obj;
    });
}

// 금액 합계
const 금액합계 = {};
[['공급가액', /공급가액[^\d]*([\d,]+)/],
 ['세액',    /세액[^\d]*([\d,]+)/],
 ['합계',    /합계[^\d]*([\d,]+)/],
 ['청구금액', /청구금액[^\d]*([\d,]+)/]]
.forEach(([k, rx]) => { const m = text.match(rx); if (m) 금액합계[k] = m[1]; });

// 거래처 정보
const 거래처 = {};
[['공급자',      /공급자[^:：]*[:：]\s*([^\n<]{1,30})/],
 ['공급받는자',  /공급받는\s*자[^:：]*[:：]\s*([^\n<]{1,30})/],
 ['사업자번호',  /사업자\s*번호[^:：]*[:：]\s*([\d\-]{1,20})/],
 ['작성일자',   /작성\s*일자[^:：]*[:：]\s*([\d\.\-\/]{1,15})/]]
.forEach(([k, rx]) => { const m = text.match(rx); if (m) 거래처[k] = m[1].trim(); });

return [{
  json: {
    거래명세서: {
      거래처정보: 거래처,
      품목목록: 품목목록,
      금액합계: 금액합계,
      원문미리보기: text.substring(0, 500),
      파싱테이블수: tables.length
    }
  }
}];
